// Pull the parsed JSON body that the Webhook node received.
// n8n exposes the POST body at $json.body when Content-Type is application/json.
const payload = $json.body ?? $json;

const id = payload.id;
const source = payload.source;
const body = payload.body;

if (id === undefined || id === null) {
  throw new Error(`Webhook payload missing 'id'. Got: ${JSON.stringify(payload)}`);
}
if (!source || typeof source !== 'string') {
  throw new Error(`Webhook payload missing 'source' string. Got: ${JSON.stringify(payload)}`);
}
if (!body || typeof body !== 'string') {
  throw new Error(`Webhook payload missing 'body' string. Got: ${JSON.stringify(payload)}`);
}

return { id, source, body };

// Recover the original validated input from two nodes upstream.
const original = $('Build Classify Prompt').item.json;

// Groq's structured response sits under choices[0].message.content as a JSON string.
const raw = $json.choices?.[0]?.message?.content;
if (!raw) {
  throw new Error(`Groq response missing content: ${JSON.stringify($json)}`);
}

let classification;
try {
  classification = JSON.parse(raw);
} catch (e) {
  throw new Error(`Groq returned non-JSON content: ${raw}`);
}

// --- Routing table (see plan §4 and docs/architecture.md) ---
function decideRoute(category, body) {
  if (category === 'Bug Report')         return 'Engineering';
  if (category === 'Incident/Outage')    return 'Engineering';
  if (category === 'Feature Request')    return 'Product';
  if (category === 'Billing Issue')      return 'Billing';
  if (category === 'Technical Question') {
    return /\b(sso|saml|okta|auth(entication)?|idp|oidc)\b/i.test(body)
      ? 'IT/Security'
      : 'Product';
  }
  return 'Triage';
}

// --- Escalation triggers (any one fires it) ---
function decideEscalation(c, body) {
  const reasons = [];

  if (typeof c.confidence === 'number' && c.confidence < 0.70) {
    reasons.push(`classifier confidence ${c.confidence} below 0.70 threshold`);
  }
  if (c.category === 'Incident/Outage') {
    reasons.push('category Incident/Outage always escalates');
  }
  const lower = body.toLowerCase();
  if (lower.includes('outage'))                  reasons.push("body contains 'outage'");
  if (lower.includes('down for all users'))      reasons.push("body contains 'down for all users'");
  if (lower.includes('multiple users affected')) reasons.push("body contains 'multiple users affected'");

  // Billing dispute amount > $500.
  // PDF says "billing error > $500" — the disputed amount, not any dollar in the body.
  // Heuristic:
  //   • 2+ amounts mentioned → dispute = max - min (e.g. "charge $1,240 but contract $980" → $260)
  //   • 1 amount mentioned   → treat it as the disputed amount
  //   • 0 amounts            → no amount-based escalation
  if (c.category === 'Billing Issue') {
    const amounts = (body.match(/\$\s*([\d,]+(?:\.\d{1,2})?)/g) || [])
      .map(a => parseFloat(a.replace(/[\$,\s]/g, '')))
      .filter(n => !isNaN(n));

    let disputed;
    if (amounts.length >= 2) {
      disputed = Math.max(...amounts) - Math.min(...amounts);
    } else if (amounts.length === 1) {
      disputed = amounts[0];
    }

    if (disputed !== undefined && disputed > 500) {
      reasons.push(`billing dispute amount $${disputed} exceeds $500 threshold`);
    }
  }

  return { flag: reasons.length > 0, reasons };
}

const category_destination = decideRoute(classification.category, original.body);
const escalation           = decideEscalation(classification, original.body);
const final_destination    = escalation.flag ? 'Escalation' : category_destination;

return {
  input: {
    id: original.id,
    source: original.source,
    body: original.body,
  },
  classification,
  routing: {
    category_destination,
    final_destination,
  },
  escalation,
};

// Pull the full upstream state from the routing node (3 nodes back).
const upstream = $('Parse Classify + Route').item.json;

// Groq's summary lives in choices[0].message.content as plain text.
const summary = $json.choices?.[0]?.message?.content?.trim();
if (!summary) {
  throw new Error(`Groq summarize response missing content: ${JSON.stringify($json)}`);
}

// Canonical output record — this shape is what we'll commit to data/outputs/results.json
// and what we ship to whichever queue the routing chose.
const record = {
  id: upstream.input.id,
  source: upstream.input.source,
  body: upstream.input.body,

  category: upstream.classification.category,
  priority: upstream.classification.priority,
  confidence: upstream.classification.confidence,

  core_issue: upstream.classification.core_issue,
  identifiers: upstream.classification.identifiers,
  urgency_signal: upstream.classification.urgency_signal,

  routing: {
    category_destination: upstream.routing.category_destination,
    final_destination:    upstream.routing.final_destination,
  },
  escalation: upstream.escalation,

  summary,
  processed_at: new Date().toISOString(),
};

return record;
